B.a1=new A.x4(0,"explanation")
B.KJ=new A.b9("What is OpenQASM?","OpenQASM (Open Quantum Assembly Language) is a text-based language for describing quantum circuits. It was developed by IBM and is the standard format used by Qiskit, many quantum hardware providers, and research papers.\n\nThink of it like assembly language for quantum computers \u2014 low-level but universal and precise.",B.a1,null,null,null)
B.Lj=new A.b9("Basic Structure",'An OpenQASM 2.0 program has this structure:\n\n  OPENQASM 2.0;\n  include "qelib1.inc";\n\n  qreg q[2];    // Declare 2 qubits\n  creg c[2];    // Declare 2 classical bits\n\n  h q[0];       // Apply H to qubit 0\n  cx q[0], q[1]; // CNOT: control=q0, target=q1\n\n  measure q -> c; // Measure all qubits\n\nLines end with semicolons. Comments use //.',B.a1,null,null,null)
B.bL=new A.x4(1,"interactive")
B.Lb=new A.b9("Your First QASM Program","Open the QASM Editor and type:\n\n  qreg q[1];\n  h q[0];\n\nThen press Run. This creates a superposition on one qubit.\nYou should see 50% |0\u27e9 and 50% |1\u27e9.",B.bL,"qreg q[1];\nh q[0];","50% |0\u27e9 and 50% |1\u27e9","Type the QASM code exactly as shown, then tap Run.")
B.Os=s([B.KJ,B.Lj,B.Lb],t.l)
B.LQ=new A.dX("qasm01",1,"Introduction to OpenQASM","The quantum assembly language",!1,B.Os)
B.a4A=new A.bG(58961,"MaterialIcons",null,!1)
B.KO=new A.b9("Gate Syntax","Single-qubit gates follow the pattern:\n\n  gatename q[index];\n\nAvailable gates:\n  h q[0];    // Hadamard\n  x q[0];    // Pauli-X (NOT)\n  y q[0];    // Pauli-Y\n  z q[0];    // Pauli-Z\n  s q[0];    // S gate (\u03c0/2 phase)\n  t q[0];    // T gate (\u03c0/4 phase)\n\nGates are applied in order, top to bottom.",B.a1,null,null,null)
B.aW=new A.x4(3,"demonstration")
B.Lu=new A.b9("Sequential Gates","Multiple gates on the same qubit execute left-to-right:\n\n  h q[0];   // |0\u27e9 \u2192 |+\u27e9\n  z q[0];   // |+\u27e9 \u2192 |-\u27e9\n  h q[0];   // |-\u27e9 \u2192 |1\u27e9\n\nThis sequence transforms |0\u27e9 to |1\u27e9 using only H and Z!",B.aW,"qreg q[1];\nh q[0];\nz q[0];\nh q[0];",null,null)
B.Lq=new A.b9("Write: HZH = X","In the QASM editor, write a program that applies H, Z, H to qubit 0.\nVerify it produces |1\u27e9 with 100% \u2014 this proves H\xb7Z\xb7H = X.",B.bL,"qreg q[1];\n// Write your gates here:\n","|1\u27e9 with 100% probability","Add three lines: h q[0]; then z q[0]; then h q[0];")
B.O5=s([B.KO,B.Lu,B.Lq],t.l)
B.LI=new A.dX("qasm02",2,"Single-Qubit Gates in QASM","h, x, y, z, s, t instructions",!1,B.O5)
B.a4s=new A.bG(57412,"MaterialIcons",null,!1)
B.L6=new A.b9("CNOT Syntax","The CNOT (controlled-X) gate uses the cx instruction:\n\n  cx q[control], q[target];\n\nIf control is |1\u27e9, target gets flipped.\n\nExample \u2014 Bell state:\n  qreg q[2];\n  h q[0];\n  cx q[0], q[1];",B.a1,null,null,null)
B.Lv=new A.b9("SWAP Syntax","SWAP exchanges two qubit states:\n\n  swap q[0], q[1];\n\nUseful when qubits need to be adjacent for hardware constraints.",B.a1,null,null,null)
B.KQ=new A.b9("Write: GHZ State","Write QASM for a 3-qubit GHZ state:\n  1. Declare 3 qubits\n  2. Apply H to q[0]\n  3. Apply CNOT from q[0] to q[1]\n  4. Apply CNOT from q[0] to q[2]\n\nExpected: only |000\u27e9 and |111\u27e9 at 50% each.",B.bL,"qreg q[3];\n// Build the GHZ state:\n","Only |000\u27e9 and |111\u27e9, each ~50%","h q[0]; then cx q[0], q[1]; then cx q[0], q[2];")
B.OA=s([B.L6,B.Lv,B.KQ],t.l)
B.LJ=new A.dX("qasm03",3,"Multi-Qubit Gates in QASM","cx, swap, and entangled circuits",!1,B.OA)
B.Lh=new A.b9("Deutsch-Jozsa in QASM","Let's implement Deutsch-Jozsa for a balanced function:\n\n  qreg q[2];\n  // Step 1: Superposition\n  h q[0];\n  h q[1];\n  // Step 2: Oracle (balanced: CX acts as f)\n  cx q[0], q[1];\n  // Step 3: Final Hadamard\n  h q[0];\n  h q[1];\n\nIf the result is NOT |00\u27e9, the function is balanced.",B.a1,null,null,null)
B.KP=new A.b9("Run Deutsch-Jozsa","The oracle here uses CNOT as a balanced function. The result should show that |00\u27e9 has zero probability \u2014 confirming the function is balanced.",B.aW,"qreg q[2];\n// Superposition\nh q[0];\nh q[1];\n// Oracle (balanced)\ncx q[0], q[1];\n// Final Hadamard\nh q[0];\nh q[1];",null,null)
B.La=new A.b9("Write: Constant Oracle","Modify the Deutsch-Jozsa QASM to use a CONSTANT function (no oracle gates). Verify that |00\u27e9 dominates the output.",B.bL,"qreg q[2];\nh q[0];\nh q[1];\n// Add constant oracle here (hint: no gates needed!)\nh q[0];\nh q[1];","|00\u27e9 with ~100% probability","A constant function f(x)=0 means no phase flips \u2014 just remove the oracle!")
B.Nk=s([B.Lh,B.KP,B.La],t.l)
B.LK=new A.dX("qasm04",4,"Building Algorithms in QASM","Deutsch-Jozsa in assembly",!1,B.Nk)
B.a4w=new A.bG(58714,"MaterialIcons",null,!1)
B.KM=new A.b9("Quantum Teleportation Setup","Quantum teleportation transfers a qubit state using entanglement + classical communication.\n\nThe circuit:\n  qreg q[3];\n  // Prepare state to teleport (e.g., H on q0)\n  h q[0];\n  // Create Bell pair between q1 and q2\n  h q[1];\n  cx q[1], q[2];\n  // Bell measurement on q0, q1\n  cx q[0], q[1];\n  h q[0];\n\nAfter measurement + correction, q2 has the original state of q0.",B.a1,null,null,null)
B.KY=new A.b9("Teleportation Circuit",'This circuit prepares a superposition on q0, creates a Bell pair on q1-q2, then performs the teleportation protocol. The state of q0 is "moved" to q2.',B.aW,"qreg q[3];\n// State to teleport\nh q[0];\n// Bell pair\nh q[1];\ncx q[1], q[2];\n// Bell measurement\ncx q[0], q[1];\nh q[0];",null,null)
B.L5=new A.b9("Bit-Flip Error Detection","Simple 3-qubit repetition code:\n\n  qreg q[3];\n  // Encode |\u03c8\u27e9 into 3 qubits\n  cx q[0], q[1];\n  cx q[0], q[2];\n  // Simulate bit-flip error on q1\n  x q[1];\n  // Syndrome detection\n  cx q[0], q[1];\n  cx q[0], q[2];\n\nMeasurement of q1 and q2 reveals which qubit was flipped.",B.a1,null,null,null)
B.Lt=new A.b9("Write: Your Own Circuit","Use everything you've learned to write a QASM circuit of your own.\n\nIdeas:\n  - 4-qubit GHZ state\n  - Quantum full adder (Toffoli from CNOT + T gates)\n  - Grover oracle for a specific bitstring\n\nThe QASM editor supports h, x, y, z, s, t, cx, swap.",B.bL,"// Your quantum program:\nqreg q[4];\n\n",null,"Start with a superposition (H gates) and build from there.")
B.OC=s([B.KM,B.KY,B.L5,B.Lt],t.l)
B.LP=new A.dX("qasm05",5,"Advanced QASM Patterns","Teleportation & error detection",!1,B.OC)
B.pn=s([B.LQ,B.LI,B.LJ,B.LK,B.LP],t.Lo)
