B.a4u=new A.bG(58331,"MaterialIcons",null,!1)
B.KU=new A.b9("What is a Bit?","A classical bit is the fundamental unit of information. It can be in one of two states:\n\n  0  (off, false)\n  1  (on, true)\n\nEvery computer program, every photo, every message you send is encoded as sequences of 0s and 1s. A byte is 8 bits, giving 2^8 = 256 possible values.",B.a1,null,null,null)
B.Ls=new A.b9("Enter the Qubit","A qubit (quantum bit) is the quantum version of a classical bit. Like a classical bit, when you measure a qubit, you get either 0 or 1.\n\nBut here's the key difference: before measurement, a qubit can exist in a superposition \u2014 a combination of both |0\u27e9 and |1\u27e9 simultaneously.\n\nWe write the qubit state as:\n  |\u03c8\u27e9 = \u03b1|0\u27e9 + \u03b2|1\u27e9\n\nwhere \u03b1 and \u03b2 are complex numbers called amplitudes. The probability of measuring 0 is |\u03b1|\xb2 and measuring 1 is |\u03b2|\xb2.",B.a1,null,null,null)
B.Lw=new A.b9("The |0\u27e9 State","Let's start with the simplest qubit state: |0\u27e9.\n\nThis is a qubit with \u03b1 = 1 and \u03b2 = 0. When measured, it always gives 0.\n\nLook at the histogram below \u2014 the probability of measuring |0\u27e9 is 100%.",B.aW,"// A single qubit in state |0\u27e9\n// No gates applied \u2014 this is the default state\nqreg q[1];",null,null)
B.KR=new A.b9("Try It Yourself","Open the Circuit Builder and create a 1-qubit circuit. Without placing any gates, run the simulation.\n\nYou should see |0\u27e9 with 100% probability.\n\nKey takeaway: Every qubit starts in the |0\u27e9 state.",B.bL,null,"You should see |0\u27e9 with 100% probability.",'Just tap "Run" without adding any gates.')
B.l4=new A.x4(2,"quiz")
B.Lm=new A.b9("Quiz: Bits vs Qubits","What makes a qubit fundamentally different from a classical bit?\n\nA) Qubits are faster\nB) Qubits can be in a superposition of 0 and 1 before measurement\nC) Qubits use less energy\nD) Qubits can store more than 2 values after measurement\n\nAnswer: B \u2014 Before measurement, a qubit can be in a superposition \u03b1|0\u27e9 + \u03b2|1\u27e9. After measurement, it collapses to either 0 or 1, just like a classical bit.",B.l4,null,null,null)
B.MJ=s([B.KU,B.Ls,B.Lw,B.KR,B.Lm],t.l)
B.LO=new A.dX("q01",1,"Classical Bits & Qubits","From 0s and 1s to quantum superposition",!0,B.MJ)
B.L9=new A.b9("Your First Quantum Gate","The Hadamard gate (H) is the most important gate in quantum computing. It transforms a definite state into an equal superposition.\n\nApplied to |0\u27e9:\n  H|0\u27e9 = (|0\u27e9 + |1\u27e9) / \u221a2 = |+\u27e9\n\nApplied to |1\u27e9:\n  H|1\u27e9 = (|0\u27e9 - |1\u27e9) / \u221a2 = |-\u27e9\n\nThe H gate matrix:\n  H = (1/\u221a2) \xd7 [[1,  1],\n                  [1, -1]]",B.a1,null,null,null)
B.Ll=new A.b9("Superposition in Action","Watch what happens when we apply H to |0\u27e9:\n\nThe qubit enters an equal superposition. Measuring it gives 0 or 1 each with 50% probability.\n\nThis is fundamentally different from randomness \u2014 the qubit is in BOTH states simultaneously until measured.",B.aW,"qreg q[1];\nh q[0];",null,null)
B.KN=new A.b9("H is Its Own Inverse","A remarkable property of the Hadamard gate: applying it twice returns you to the original state!\n\n  H(H|0\u27e9) = H|+\u27e9 = |0\u27e9\n\nThis is because H \xd7 H = I (the identity matrix). Try it below \u2014 two H gates cancel out.",B.aW,"qreg q[1];\nh q[0];\nh q[0];",null,null)
B.Lk=new A.b9("Build a Superposition","Open the Circuit Builder:\n1. Create a 1-qubit circuit\n2. Place an H gate on qubit 0\n3. Run the simulation\n\nYou should see |0\u27e9 and |1\u27e9 each with \u224850% probability.",B.bL,null,"50% |0\u27e9 and 50% |1\u27e9","Drag the H gate from the palette onto the qubit wire.")
B.Oi=s([B.L9,B.Ll,B.KN,B.Lk],t.l)
B.LN=new A.dX("q02",2,"The Hadamard Gate","Creating superposition states",!0,B.Oi)
B.Li=new A.b9("The Born Rule","When we measure a qubit in state |\u03c8\u27e9 = \u03b1|0\u27e9 + \u03b2|1\u27e9, we get:\n\n  Outcome 0 with probability |\u03b1|\xb2\n  Outcome 1 with probability |\u03b2|\xb2\n\nSince total probability must be 1:\n  |\u03b1|\xb2 + |\u03b2|\xb2 = 1\n\nThis is called the Born Rule, named after Max Born (1926). It connects the abstract amplitudes to physically observable probabilities.",B.a1,null,null,null)
B.Lg=new A.b9("Measurement Collapses the State",'After measurement, the superposition is destroyed. The qubit "collapses" into whichever state was observed.\n\nIf you measure |+\u27e9 and get 0, the qubit is now in state |0\u27e9. If you measure again, you\'ll get 0 with certainty.\n\nThis is why quantum computation must be done BEFORE measurement \u2014 you can\'t "peek" at a qubit without changing it.',B.a1,null,null,null)
B.Le=new A.b9("Statistical Measurement","In real quantum computers (and our simulator), we run the circuit many times (\"shots\") to estimate probabilities.\n\nWith 1024 shots on a |+\u27e9 state, you'll get approximately:\n  |0\u27e9: ~512 counts (~50%)\n  |1\u27e9: ~512 counts (~50%)\n\nBut not exactly 512 \u2014 there's statistical noise, just like flipping a fair coin.",B.aW,"qreg q[1];\nh q[0];",null,null)
B.Lf=new A.b9("Multiple Qubits","With 2 qubits, we have 4 possible outcomes: |00\u27e9, |01\u27e9, |10\u27e9, |11\u27e9.\n\nApplying H to both qubits creates an equal superposition of ALL four states:\n  |\u03c8\u27e9 = \xbd(|00\u27e9 + |01\u27e9 + |10\u27e9 + |11\u27e9)\n\nEach outcome has 25% probability.",B.aW,"qreg q[2];\nh q[0];\nh q[1];",null,null)
B.L0=new A.b9("Quiz: Probability","If a qubit is in state |\u03c8\u27e9 = (\u221a3/2)|0\u27e9 + (1/2)|1\u27e9, what is the probability of measuring |1\u27e9?\n\nA) 1/2\nB) 1/4\nC) 3/4\nD) \u221a3/2\n\nAnswer: B \u2014 The probability is |\u03b2|\xb2 = |1/2|\xb2 = 1/4 = 25%.",B.l4,null,null,null)
B.N1=s([B.Li,B.Lg,B.Le,B.Lf,B.L0],t.l)
B.LF=new A.dX("q03",3,"Measurement & Probability","Collapsing the quantum state",!0,B.N1)
B.a4v=new A.bG(58688,"MaterialIcons",null,!1)
B.L8=new A.b9("The Pauli-X Gate (NOT)","The X gate is the quantum NOT gate. It flips |0\u27e9 to |1\u27e9 and vice versa:\n\n  X|0\u27e9 = |1\u27e9\n  X|1\u27e9 = |0\u27e9\n\nMatrix:\n  X = [[0, 1],\n       [1, 0]]\n\nOn the Bloch sphere, X is a 180\xb0 rotation around the X-axis.",B.a1,null,null,null)
B.L4=new A.b9("X Gate Demo","Watch the X gate flip |0\u27e9 to |1\u27e9. The Bloch sphere arrow moves from the north pole to the south pole.",B.aW,"qreg q[1];\nx q[0];",null,null)
B.KH=new A.b9("The Pauli-Y Gate","The Y gate combines a bit flip with a phase flip:\n\n  Y|0\u27e9 = i|1\u27e9\n  Y|1\u27e9 = -i|0\u27e9\n\nMatrix:\n  Y = [[0, -i],\n       [i,  0]]\n\nOn the Bloch sphere, Y is a 180\xb0 rotation around the Y-axis.",B.a1,null,null,null)
B.L1=new A.b9("The Pauli-Z Gate","The Z gate flips the phase of |1\u27e9 without changing |0\u27e9:\n\n  Z|0\u27e9 = |0\u27e9\n  Z|1\u27e9 = -|1\u27e9\n\nMatrix:\n  Z = [[1,  0],\n       [0, -1]]\n\nZ doesn't change measurement probabilities (it only affects phase), but phases matter in multi-qubit circuits and interference.",B.a1,null,null,null)
B.KF=new A.b9("Z Gate on Superposition","Apply H then Z to see phase in action:\n  H|0\u27e9 = |+\u27e9 = (|0\u27e9 + |1\u27e9)/\u221a2\n  Z|+\u27e9 = |-\u27e9 = (|0\u27e9 - |1\u27e9)/\u221a2\n\nThe probabilities are still 50/50, but the PHASE has changed. If we apply another H, we get |1\u27e9 instead of |0\u27e9!",B.aW,"qreg q[1];\nh q[0];\nz q[0];\nh q[0];",null,null)
B.Lz=new A.b9("Build: X Gate Circuit","Create a 1-qubit circuit and apply the X gate. Verify that measurement gives |1\u27e9 with 100% probability.",B.bL,null,"|1\u27e9 with 100% probability","Place a single X gate on qubit 0.")
B.Og=s([B.L8,B.L4,B.KH,B.L1,B.KF,B.Lz],t.l)
B.LR=new A.dX("q04",4,"Pauli Gates (X, Y, Z)","Rotations on the Bloch sphere",!1,B.Og)
B.Jf=new A.bG(58608,"MaterialIcons",null,!1)
B.L2=new A.b9("Geometry of a Qubit","Any single-qubit state can be written as:\n\n  |\u03c8\u27e9 = cos(\u03b8/2)|0\u27e9 + e^(i\u03c6)sin(\u03b8/2)|1\u27e9\n\nwhere \u03b8 \u2208 [0, \u03c0] and \u03c6 \u2208 [0, 2\u03c0).\n\nThis maps every qubit state to a point on a sphere:\n  x = sin(\u03b8)cos(\u03c6)\n  y = sin(\u03b8)sin(\u03c6)\n  z = cos(\u03b8)\n\nThis is the Bloch sphere. |0\u27e9 is the north pole (z=1), |1\u27e9 is the south pole (z=-1).",B.a1,null,null,null)
B.KV=new A.b9("Key Points on the Sphere","North pole:  |0\u27e9         \u2192 (0, 0, 1)\nSouth pole:  |1\u27e9         \u2192 (0, 0, -1)\n+X axis:     |+\u27e9 = H|0\u27e9  \u2192 (1, 0, 0)\n-X axis:     |-\u27e9 = H|1\u27e9  \u2192 (-1, 0, 0)\n+Y axis:     |+i\u27e9        \u2192 (0, 1, 0)\n-Y axis:     |-i\u27e9        \u2192 (0, -1, 0)\n\nGates are rotations on this sphere:\n  X \u2192 180\xb0 around X-axis\n  Y \u2192 180\xb0 around Y-axis\n  Z \u2192 180\xb0 around Z-axis\n  H \u2192 180\xb0 around the X+Z axis",B.a1,null,null,null)
B.KZ=new A.b9("Explore the Sphere","In the Circuit Builder, try each gate one at a time on a single qubit and watch the Bloch sphere arrow move:\n\n1. Start with no gates (arrow at north pole = |0\u27e9)\n2. Apply X (arrow flips to south pole = |1\u27e9)\n3. Clear and apply H (arrow moves to +X axis = |+\u27e9)\n4. Clear and apply H then S (arrow moves toward +Y axis)",B.bL,null,null,"Use the Bloch Sphere tab to see the arrow move as you add gates.")
B.Nd=s([B.L2,B.KV,B.KZ],t.l)
B.LE=new A.dX("q05",5,"The Bloch Sphere","Visualizing single-qubit states",!1,B.Nd)
B.a4B=new A.bG(59011,"MaterialIcons",null,!1)
B.KW=new A.b9("What is Phase?","In |\u03c8\u27e9 = \u03b1|0\u27e9 + \u03b2|1\u27e9, the relative phase between \u03b1 and \u03b2 determines how the qubit interferes in circuits.\n\nPhase is invisible to single measurements, but crucial for quantum algorithms.",B.a1,null,null,null)
B.LB=new A.b9("The S Gate (\u221aZ)",'The S gate applies a \u03c0/2 (90\xb0) phase rotation:\n\n  S|0\u27e9 = |0\u27e9\n  S|1\u27e9 = i|1\u27e9\n\nMatrix:\n  S = [[1, 0],\n       [0, i]]\n\nOn the Bloch sphere, S is a 90\xb0 rotation around the Z-axis. Note: S\xb2 = Z, so S is the "square root of Z".',B.a1,null,null,null)
B.Lo=new A.b9("The T Gate (\u221aS)",'The T gate applies a \u03c0/4 (45\xb0) phase rotation:\n\n  T|0\u27e9 = |0\u27e9\n  T|1\u27e9 = e^(i\u03c0/4)|1\u27e9\n\nMatrix:\n  T = [[1, 0],\n       [0, e^(i\u03c0/4)]]\n\nT is the "\u03c0/8 gate" (the overall phase factor). It\'s critical for quantum error correction and is one of the hardest gates to implement on real quantum hardware.',B.a1,null,null,null)
B.LA=new A.b9("Phase Changes Direction","Starting from |+\u27e9, the S gate rotates the state on the equator of the Bloch sphere:\n\n  H|0\u27e9 = |+\u27e9  (pointing along +X)\n  S|+\u27e9 = |+i\u27e9 (pointing along +Y)\n\nThe probabilities are still 50/50, but the state has moved on the sphere.",B.aW,"qreg q[1];\nh q[0];\ns q[0];",null,null)
B.Ol=s([B.KW,B.LB,B.Lo,B.LA],t.l)
B.LD=new A.dX("q06",6,"Phase Gates (S, T)","Precision phase rotations",!1,B.Ol)
B.a4t=new A.bG(58240,"MaterialIcons",null,!1)
B.KX=new A.b9("The CNOT Gate","The Controlled-NOT (CNOT or CX) is the fundamental two-qubit gate.\n\nIt has a control qubit and a target qubit:\n  If control = |0\u27e9: target unchanged\n  If control = |1\u27e9: target is flipped (X applied)\n\n  CNOT|00\u27e9 = |00\u27e9\n  CNOT|01\u27e9 = |01\u27e9\n  CNOT|10\u27e9 = |11\u27e9\n  CNOT|11\u27e9 = |10\u27e9",B.a1,null,null,null)
B.Ly=new A.b9("Creating Entanglement","The most powerful concept in quantum computing: entanglement.\n\nApply H to qubit 0, then CNOT with qubit 0 as control:\n  1. |00\u27e9\n  2. H on q0: (|0\u27e9+|1\u27e9)/\u221a2 \u2297 |0\u27e9 = (|00\u27e9+|10\u27e9)/\u221a2\n  3. CNOT: (|00\u27e9+|11\u27e9)/\u221a2\n\nThis is a Bell state! The qubits are now entangled \u2014 measuring one instantly determines the other.",B.a1,null,null,null)
B.KL=new A.b9("Bell State Demo","This circuit creates the Bell state |\u03a6+\u27e9 = (|00\u27e9+|11\u27e9)/\u221a2.\n\nNotice: the only measurement outcomes are |00\u27e9 and |11\u27e9, each with 50%. You NEVER see |01\u27e9 or |10\u27e9 \u2014 the qubits are perfectly correlated.",B.aW,"qreg q[2];\nh q[0];\ncx q[0], q[1];",null,null)
B.LC=new A.b9("Build a Bell State","Create a 2-qubit circuit:\n1. Place H on qubit 0\n2. Place CNOT with control=q0, target=q1\n3. Run and verify only |00\u27e9 and |11\u27e9 appear",B.bL,null,"Only |00\u27e9 and |11\u27e9, each ~50%","Place H first, then CNOT. The CNOT will automatically use the next qubit.")
B.KT=new A.b9("GHZ State (3 Qubits)","Extend entanglement to 3 qubits:\n  H on q0, CNOT q0\u2192q1, CNOT q0\u2192q2\n\nResult: (|000\u27e9 + |111\u27e9)/\u221a2 \u2014 the GHZ state.\nAll three qubits are entangled. Measuring any one determines the others.",B.aW,"qreg q[3];\nh q[0];\ncx q[0], q[1];\ncx q[0], q[2];",null,null)
B.Oh=s([B.KX,B.Ly,B.KL,B.LC,B.KT],t.l)
B.LL=new A.dX("q07",7,"Entanglement (CNOT)","Multi-qubit systems & Bell states",!1,B.Oh)
B.a4z=new A.bG(58917,"MaterialIcons",null,!1)
B.Ld=new A.b9("The SWAP Gate","SWAP exchanges the states of two qubits:\n\n  SWAP|01\u27e9 = |10\u27e9\n  SWAP|10\u27e9 = |01\u27e9\n\nSWAP can be decomposed into 3 CNOT gates:\n  SWAP = CNOT(1,0) \xb7 CNOT(0,1) \xb7 CNOT(1,0)",B.a1,null,null,null)
B.Lc=new A.b9("SWAP Demo","We prepare |10\u27e9 (X on q0) then SWAP \u2192 |01\u27e9.",B.aW,"qreg q[2];\nx q[0];\nswap q[0], q[1];",null,null)
B.KI=new A.b9("Circuit Identities","Important identities for circuit optimization:\n\n  H\xb7H = I   (Hadamard is self-inverse)\n  X\xb7X = I   (double NOT = nothing)\n  S\xb7S = Z   (two S gates = Z)\n  T\xb7T = S   (two T gates = S)\n  Z = S\xb2    (Z is S squared)\n  S = T\xb2    (S is T squared)\n\nThese let you simplify circuits and reduce gate count.",B.a1,null,null,null)
B.L3=new A.b9("Verify: T\xb7T = S","Build two circuits and compare their Bloch spheres:\n1. Circuit A: H, then S\n2. Circuit B: H, then T, then T\n\nBoth should produce the same state.",B.bL,null,"Both circuits produce the same Bloch sphere position","Build each circuit separately and compare the Bloch sphere coordinates.")
B.Oj=s([B.Ld,B.Lc,B.KI,B.L3],t.l)
B.LM=new A.dX("q08",8,"SWAP & Circuit Identities","Equivalent circuits & simplification",!1,B.Oj)
B.a4y=new A.bG(58848,"MaterialIcons",null,!1)
B.L7=new A.b9("The Problem","Given a function f: {0,1}^n \u2192 {0,1}, determine if f is:\n  Constant: f(x) = 0 for all x, or f(x) = 1 for all x\n  Balanced: f(x) = 0 for exactly half the inputs\n\nClassically, you need 2^(n-1) + 1 queries in the worst case.\nQuantum: just ONE query! This is exponential speedup.",B.a1,null,null,null)
B.Lr=new A.b9("The Algorithm","Deutsch-Jozsa algorithm:\n\n1. Start with n qubits in |0...0\u27e9\n2. Apply H to each qubit \u2192 equal superposition\n3. Apply the oracle (encodes f as phase flips)\n4. Apply H to each qubit again\n5. Measure\n\nIf f is constant \u2192 measure |0...0\u27e9 with certainty\nIf f is balanced \u2192 NEVER measure |0...0\u27e9\n\nThis is implemented in QuantumLab using the PFQVS engine.",B.a1,null,null,null)
B.Lp=new A.b9("Constant Function","Testing f(x) = 0 (constant). The algorithm returns |00\u27e9 with high probability, confirming the function is constant.",B.aW,"// Deutsch-Jozsa with constant f(x) = 0\n// Result: |00\u27e9 dominant \u2192 constant\nqreg q[2];\nh q[0];\nh q[1];\n// No oracle (f=0 means no phase flips)\nh q[0];\nh q[1];",null,null)
B.Ln=new A.b9("Balanced Function","Testing a balanced function: f flips phase for half the inputs. The algorithm returns a non-|00\u27e9 state, confirming it's balanced.",B.aW,"// Deutsch-Jozsa with balanced f (CNOT acts as oracle)\nqreg q[2];\nh q[0];\nh q[1];\ncx q[0], q[1];\nh q[0];\nh q[1];",null,null)
B.ND=s([B.L7,B.Lr,B.Lp,B.Ln],t.l)
B.LH=new A.dX("q09",9,"Deutsch-Jozsa Algorithm","Quantum speedup for function testing",!1,B.ND)
B.a4x=new A.bG(58727,"MaterialIcons",null,!1)
B.L_=new A.b9("The Search Problem","Given an unsorted database of N items, find one marked item.\n\nClassical: O(N) queries (check each item)\nGrover's: O(\u221aN) queries \u2014 quadratic speedup!\n\nFor N = 1,000,000:\n  Classical: ~1,000,000 queries\n  Grover's: ~1,000 queries",B.a1,null,null,null)
B.Lx=new A.b9("How It Works","Grover's algorithm has two key operations, repeated ~(\u03c0/4)\u221aN times:\n\n1. Oracle: Flip the phase of the target state\n   |target\u27e9 \u2192 -|target\u27e9\n\n2. Diffusion: Reflect all amplitudes about the mean\n   Each amplitude a_i \u2192 2\xb7mean - a_i\n\nThis gradually amplifies the target state's amplitude while suppressing all others.",B.a1,null,null,null)
B.KS=new A.b9("Amplitude Amplification","Start with uniform superposition (all N states equal).\n\nEach Grover iteration:\n  1. Oracle marks the target (inverts its amplitude)\n  2. Diffusion boosts amplitudes below average and reduces those above\n  3. Target amplitude grows, others shrink\n\nAfter ~(\u03c0/4)\u221aN iterations, the target has nearly 100% probability.\n\nToo many iterations and the amplitude overshoots and decreases!",B.a1,null,null,null)
B.KK=new A.b9("Grover Demo (3 qubits)","Searching for |101\u27e9 among 8 states (3 qubits).\nOptimal iterations: round(\u03c0/4 \xb7 \u221a8) \u2248 2.\n\nAfter 2 iterations, |101\u27e9 should dominate the histogram.",B.aW,"// Grover's search for |101\u27e9 on 3 qubits\n// Uses the built-in groversSearch algorithm\nqreg q[3];\nh q[0];\nh q[1];\nh q[2];\n// Oracle + Diffusion handled by PFQVS engine",null,null)
B.KG=new A.b9("Quiz: Grover Complexity","For a database of 256 items, approximately how many Grover iterations are needed?\n\nA) 256\nB) 128\nC) 16\nD) 13\n\nAnswer: D \u2014 Iterations = round(\u03c0/4 \xd7 \u221a256) = round(\u03c0/4 \xd7 16) = round(12.57) \u2248 13.",B.l4,null,null,null)
B.OF=s([B.L_,B.Lx,B.KS,B.KK,B.KG],t.l)
B.LG=new A.dX("q10",10,"Grover's Search Algorithm","Finding needles in haystacks",!1,B.OF)
